import { useEffect, useState } from "react";
import { useQuery } from "@tanstack/react-query";
import Markdown from "../components/Markdown";
import { useT } from "../i18n/useT";
import { listStores } from "../lib/stores";
import { listPreorders } from "../lib/preorders";
import { emailReorder } from "../lib/email";
import { parseTotals } from "../lib/poParse";
import { useSelectedStore } from "../stores/selectedStore";
import {
  usePanel, useHistory, moveBackToHistory, type VendorEntry,
} from "../stores/poStore";

/**
 * Active PO review panel (left). Shows all panel vendors for the
 * currently selected store. Each vendor card has copy/email/archive.
 *
 * On first load, also calls /api/admin/preorders -> seeds history
 * with any server-side rows the user hasn't seen yet (dedup against
 * panel + history). Same pattern as legacy loadPreorders().
 */
export default function POPanelPage() {
  const t = useT();
  const { storeId, setStoreId } = useSelectedStore();
  const stores = useQuery({ queryKey: ["stores"], queryFn: listStores });
  const panel  = usePanel();
  const hist   = useHistory();
  const [hydrated, setHydrated] = useState(false);

  useEffect(() => {
    if (!storeId && stores.data && stores.data.length > 0) {
      setStoreId(String(stores.data[0].store_id));
    }
  }, [storeId, stores.data, setStoreId]);

  // One-shot pre-orders hydrate on mount (parity with legacy).
  useEffect(() => {
    if (hydrated) return;
    setHydrated(true);
    (async () => {
      try {
        const items = await listPreorders();
        const seen = new Set([
          ...panel.vendors.map((v) => `${v.storeId}|${v.vendorId}`),
          ...hist.entries.map((v) => `${v.storeId}|${v.vendorId}`),
        ]);
        const fresh: VendorEntry[] = items
          .filter((it) => !seen.has(`${it.store_id}|${it.vendor_id}`))
          .map((it) => ({
            id: `pre_${it.store_id}_${it.vendor_id}`,
            storeId: it.store_id,
            storeName: it.store_name,
            vendorId: it.vendor_id,
            vendorName: it.vendor_name,
            ts: it.ts || Date.now(),
            markdown: it.markdown || "",
            cases: it.cases || 0,
            amount: it.amount || 0,
            preGenerated: true,
          }));
        if (fresh.length) hist.replaceAll([...fresh, ...hist.entries]);
      } catch { /* best-effort */ }
    })();
  }, [hydrated, panel.vendors, hist]);

  const vs = panel.vendors.filter((v) => v.storeId === storeId);

  let grandCases = 0, grandAmount = 0;
  for (const v of vs) {
    const tot = parseTotals(v.markdown || "");
    grandCases  += tot.cases;
    grandAmount += tot.amount;
  }
  const grandAmtTxt = grandAmount.toLocaleString(undefined, { maximumFractionDigits: 0 });

  return (
    <section className="space-y-4 max-w-5xl">
      <div className="flex items-center gap-3">
        <label className="text-sm">{t("store.label")}</label>
        <select
          value={storeId}
          onChange={(e) => setStoreId(e.target.value)}
          className="border rounded px-2 py-1"
        >
          {(stores.data || []).map((s) => (
            <option key={s.store_id} value={s.store_id}>
              {s.store_id} -- {s.name}
            </option>
          ))}
        </select>
      </div>

      {vs.length === 0 ? (
        <p className="text-slate-500 text-sm">{t("po.empty")}</p>
      ) : (
        <>
          <div className="text-sm">
            <span className="text-slate-500">{t("po.total")}:</span>{" "}
            <b>{grandCases}</b> {t("po.cases")} &middot; <b>${grandAmtTxt}</b> &middot;{" "}
            {vs.length} {t("po.vendors")}
          </div>
          <div className="space-y-3">
            {vs.map((v) => (
              <VendorCard key={v.id} v={v} />
            ))}
          </div>
        </>
      )}
    </section>
  );
}

function VendorCard({ v }: { v: VendorEntry }) {
  const t = useT();
  const fresh = parseTotals(v.markdown || "");
  const [busy, setBusy] = useState(false);

  async function copy() {
    await navigator.clipboard.writeText(v.markdown || "");
  }

  async function email() {
    setBusy(true);
    try {
      const r = await emailReorder({
        store_id: v.storeId,
        vendor_id: v.vendorId,
        markdown: v.markdown,
        cases: fresh.cases,
        amount: fresh.amount,
      });
      alert(`email: ${r.status} sent=${r.sent ?? 0}/${r.total ?? 0}`);
    } catch (e) {
      alert(`email failed: ${e}`);
    } finally {
      setBusy(false);
    }
  }

  function archive() {
    moveBackToHistory(v.id);
  }

  return (
    <details className="border rounded bg-white" open>
      <summary className="cursor-pointer p-3 flex items-center gap-3 select-none">
        <span className="font-medium">{v.vendorName}</span>
        <span className="text-xs text-slate-500">
          {fresh.cases} {t("po.cases")} -- $
          {fresh.amount.toLocaleString(undefined, { maximumFractionDigits: 0 })}
        </span>
        <span className="ml-auto flex gap-2 text-xs">
          <button
            onClick={(e) => { e.preventDefault(); copy(); }}
            className="underline"
          >
            {t("po.copy")}
          </button>
          <button
            onClick={(e) => { e.preventDefault(); email(); }}
            disabled={busy}
            className="underline disabled:opacity-50"
          >
            {t("po.email")}
          </button>
          <button
            onClick={(e) => { e.preventDefault(); archive(); }}
            className="underline text-amber-700"
          >
            {t("po.retire")}
          </button>
        </span>
      </summary>
      <div className="p-3 border-t">
        <Markdown text={v.markdown || ""} />
      </div>
    </details>
  );
}
