import { api } from "./api";

export interface Vendor {
  id?: string;
  vendor_id?: string;
  name: string;
}

export async function listVendors(storeId: string): Promise<Vendor[]> {
  return api<Vendor[]>(`/api/stores/${encodeURIComponent(storeId)}/vendors`);
}

export interface BatchVendor {
  vendor_id: string;
  vendor_name: string;
  kind: "transfer" | "order";
}

export async function listBatchVendors(storeId: string): Promise<BatchVendor[]> {
  const r = await api<{ vendors: BatchVendor[] }>(
    `/api/admin/po-batch/${encodeURIComponent(storeId)}/vendors`,
  );
  return r.vendors || [];
}
