import { useQuery } from "@tanstack/react-query";
import { api } from "../lib/api";
import { useT } from "../i18n/useT";

interface Holiday {
  name: string;
  date?: string;
  recurrence?: string;
  demand_multiplier?: number;
  notes?: string;
}

interface UpcomingResponse {
  upcoming: Holiday[];
}

export default function HolidayBanner() {
  const t = useT();
  const q = useQuery({
    queryKey: ["holidays", "upcoming", 7],
    queryFn:  () => api<UpcomingResponse>("/api/holidays/upcoming?business_days=7"),
    staleTime: 60 * 60 * 1000,    // 1 hour
  });
  if (q.isLoading || q.isError) return null;
  const list = q.data?.upcoming || [];
  if (list.length === 0) return null;
  return (
    <div className="bg-amber-50 border-l-4 border-amber-400 px-3 py-2 text-sm">
      <span className="font-medium mr-2">{t("holiday.upcoming")}:</span>
      {list.slice(0, 3).map((h, i) => (
        <span key={i} className="mr-3">
          {h.name}
          {h.date && <span className="text-slate-500"> ({h.date})</span>}
          {h.demand_multiplier && (
            <span className="text-amber-700 ml-1">x{h.demand_multiplier}</span>
          )}
        </span>
      ))}
    </div>
  );
}
