import { useEffect, useState } from "react";
import { Link, useParams } from "react-router-dom";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import {
  getDraft, previewDraft, editDraft, rescanDraft,
  type DraftLine,
} from "../../lib/drafts";
import { useT } from "../../i18n/useT";

/**
 * Draft review surface:
 *   - vendor metadata header (editable)
 *   - line table (sku / name / qty / cost / total / confidence)
 *     with inline edit + add row + delete row
 *   - chat-style rescan: send a hint to Gemini, get refined lines back
 *   - HTML preview block at the bottom (server-rendered)
 */
export default function DraftDetailPage() {
  const { draftId = "" } = useParams();
  const t  = useT();
  const qc = useQueryClient();

  const meta = useQuery({
    queryKey: ["draft", draftId],
    queryFn:  () => getDraft(draftId),
    enabled:  !!draftId,
  });
  const preview = useQuery({
    queryKey: ["draft", draftId, "preview"],
    queryFn:  () => previewDraft(draftId),
    enabled:  !!draftId,
  });

  const [lines, setLines] = useState<DraftLine[]>([]);
  const [vendorName, setVendorName] = useState("");
  const [invoiceNo,  setInvoiceNo]  = useState("");
  const [invoiceDt,  setInvoiceDt]  = useState("");
  const [hint, setHint] = useState("");
  const [errMsg, setErrMsg] = useState("");

  // Hydrate local state from server payload once.
  useEffect(() => {
    if (!meta.data) return;
    setLines(meta.data.lines || []);
    setVendorName(meta.data.vendor_name || "");
    setInvoiceNo(meta.data.vendor_invoice_no || "");
    setInvoiceDt(meta.data.invoice_date || "");
  }, [meta.data]);

  const save = useMutation({
    mutationFn: () => editDraft(draftId, {
      lines,
      vendor_name: vendorName,
      vendor_invoice_no: invoiceNo,
      invoice_date: invoiceDt,
    }),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["draft", draftId] });
      qc.invalidateQueries({ queryKey: ["draft", draftId, "preview"] });
    },
    onError: (e) => setErrMsg(String(e)),
  });

  const rescan = useMutation({
    mutationFn: () => rescanDraft(draftId, hint),
    onSuccess: (r) => {
      setLines(r.lines || []);
      setHint("");
      qc.invalidateQueries({ queryKey: ["draft", draftId] });
      qc.invalidateQueries({ queryKey: ["draft", draftId, "preview"] });
    },
    onError: (e) => setErrMsg(String(e)),
  });

  if (!draftId)        return <p>missing draft id</p>;
  if (meta.isLoading)  return <p>{t("common.loading")}</p>;
  if (meta.isError)    return <p className="text-red-700">{String(meta.error)}</p>;
  if (!meta.data)      return null;
  const d = meta.data;

  function addLine() {
    setLines((ls) => [...ls, {
      sku: "", product_name: "", qty: 0, unit_cost: 0, line_total: 0,
    }]);
  }
  function delLine(i: number) {
    setLines((ls) => ls.filter((_, idx) => idx !== i));
  }
  function patchLine(i: number, patch: Partial<DraftLine>) {
    setLines((ls) => ls.map((ln, idx) => idx === i ? { ...ln, ...patch } : ln));
  }

  return (
    <section className="space-y-4 max-w-6xl">
      <Link to="/admin/drafts" className="text-blue-700 underline text-sm">
        &lt;- drafts
      </Link>
      <header className="space-y-2">
        <h2 className="text-lg font-semibold">
          Draft {d.id} -- store {d.store_id} -- {d.status}
        </h2>
        <p className="text-xs text-slate-500">
          created {new Date(d.created_at * 1000).toLocaleString()}
        </p>
        <div className="grid grid-cols-3 gap-2 text-sm">
          <Field label="vendor" value={vendorName} onChange={setVendorName} />
          <Field label="invoice no" value={invoiceNo} onChange={setInvoiceNo} />
          <Field label="invoice date" value={invoiceDt} onChange={setInvoiceDt} />
        </div>
      </header>

      <div>
        <div className="flex items-center gap-2 mb-2">
          <h3 className="font-medium">{t("draft.lines")} ({lines.length})</h3>
          <button onClick={addLine} className="text-xs underline">{t("draft.add_line")}</button>
          <button
            onClick={() => save.mutate()}
            disabled={save.isPending}
            className="ml-auto bg-slate-900 text-white px-3 py-1 rounded text-sm disabled:opacity-50"
          >
            {save.isPending ? "..." : t("common.save")}
          </button>
        </div>
        <div className="overflow-x-auto">
          <table className="text-xs w-full border-collapse">
            <thead className="bg-slate-100">
              <tr>
                <th className="text-left p-1 w-32">{t("draft.col.sku")}</th>
                <th className="text-left p-1">{t("draft.col.name")}</th>
                <th className="text-right p-1 w-16">{t("draft.col.qty")}</th>
                <th className="text-right p-1 w-20">{t("draft.col.cost")}</th>
                <th className="text-right p-1 w-24">{t("draft.col.total")}</th>
                <th className="text-right p-1 w-16">{t("draft.col.conf")}</th>
                <th className="w-8"></th>
              </tr>
            </thead>
            <tbody>
              {lines.map((ln, i) => (
                <tr key={i} className="border-b">
                  <td className="p-1">
                    <Inp v={ln.sku || ""} on={(v) => patchLine(i, { sku: v })} mono />
                  </td>
                  <td className="p-1">
                    <Inp
                      v={ln.product_name || ln.description || ""}
                      on={(v) => patchLine(i, { product_name: v })}
                    />
                  </td>
                  <td className="p-1 text-right">
                    <NumInp v={ln.qty} on={(v) => patchLine(i, { qty: v })} />
                  </td>
                  <td className="p-1 text-right">
                    <NumInp v={ln.unit_cost} on={(v) => patchLine(i, { unit_cost: v })} />
                  </td>
                  <td className="p-1 text-right">
                    <NumInp v={ln.line_total} on={(v) => patchLine(i, { line_total: v })} />
                  </td>
                  <td className="p-1 text-right text-slate-500">
                    {ln.confidence != null ? Math.round(ln.confidence * 100) : "-"}
                  </td>
                  <td className="p-1 text-center">
                    <button
                      onClick={() => delLine(i)}
                      className="text-red-700 underline"
                      title="delete row"
                    >x</button>
                  </td>
                </tr>
              ))}
              {lines.length === 0 && (
                <tr>
                  <td colSpan={7} className="p-2 text-slate-500 text-center">no lines</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="bg-slate-50 border rounded p-3 space-y-2">
        <h3 className="font-medium text-sm">{t("ocr.rescan")}</h3>
        {(d.hints && d.hints.length > 0) && (
          <ul className="text-xs space-y-1 max-h-40 overflow-y-auto">
            {d.hints.map((h, i) => (
              <li key={i} className="bg-white border rounded px-2 py-1">
                <span className="text-slate-400 mr-2">
                  {new Date(h.ts * 1000).toLocaleTimeString()}
                </span>
                {h.hint}
              </li>
            ))}
          </ul>
        )}
        <div className="flex gap-2">
          <input
            value={hint}
            onChange={(e) => setHint(e.target.value)}
            placeholder={t("ocr.hint_ph")}
            className="flex-1 border rounded px-3 py-2 text-sm"
            onKeyDown={(e) => { if (e.key === "Enter") rescan.mutate(); }}
          />
          <button
            onClick={() => rescan.mutate()}
            disabled={rescan.isPending}
            className="bg-emerald-700 text-white px-3 py-2 rounded text-sm disabled:opacity-50"
          >
            {rescan.isPending ? t("ocr.uploading") : t("ocr.rescan")}
          </button>
        </div>
      </div>

      {errMsg && <p className="text-sm text-red-700">{errMsg}</p>}

      {preview.data && (
        <div>
          <h3 className="font-medium text-sm mb-1">Preview</h3>
          <div
            className="border rounded p-3 bg-white text-sm"
            dangerouslySetInnerHTML={{ __html: preview.data.html }}
          />
        </div>
      )}
    </section>
  );
}

function Field({ label, value, onChange }: {
  label: string; value: string; onChange: (v: string) => void;
}) {
  return (
    <label className="text-xs">
      <span className="text-slate-500 block">{label}</span>
      <input
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="w-full border rounded px-2 py-1 text-sm"
      />
    </label>
  );
}

function Inp({ v, on, mono }: { v: string; on: (v: string) => void; mono?: boolean }) {
  return (
    <input
      value={v}
      onChange={(e) => on(e.target.value)}
      className={"w-full border rounded px-1 py-0.5 " + (mono ? "font-mono" : "")}
    />
  );
}

function NumInp({ v, on }: { v: number | undefined; on: (v: number) => void }) {
  return (
    <input
      type="number"
      inputMode="decimal"
      value={v ?? ""}
      onChange={(e) => on(parseFloat(e.target.value) || 0)}
      className="w-full border rounded px-1 py-0.5 text-right tabular-nums"
    />
  );
}
