import { useEffect, useRef, useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { listStores } from "../lib/stores";
import { listVendors } from "../lib/vendors";
import { useSelectedStore } from "../stores/selectedStore";
import { openReorder, type ReorderHandle } from "../lib/reorderWS";
import { upsertPreorder } from "../lib/preorders";
import { emailReorder } from "../lib/email";
import { parseTotals } from "../lib/poParse";
import { usePanel } from "../stores/poStore";
import Markdown from "../components/Markdown";
import { useT } from "../i18n/useT";
import { listTasks, enqueueTask } from "../lib/queue";

/**
 * Single-vendor PO generation. Mirrors legacy generatePO() flow:
 *   - select store + vendor
 *   - open WS, dispatch {action:"generate"} on mount
 *   - stream tokens (visible in token tail) + po_replace updates
 *     the markdown panel atomically
 *   - on done: persist preorder + push to local panel store
 *   - chat-style refine box sends {action:"edit", message:"..."}
 *
 * The whole-vendor markdown (po_replace) is the truth; token tail
 * is for liveness feedback only.
 */
export default function GeneratePage() {
  const t = useT();
  const { storeId, setStoreId } = useSelectedStore();
  const [vendorId, setVendorId] = useState("");

  const stores = useQuery({ queryKey: ["stores"], queryFn: listStores });
  const vendors = useQuery({
    queryKey: ["vendors", storeId],
    queryFn: () => listVendors(storeId),
    enabled: !!storeId,
  });

  // Detect "batch is running for this store" so we can offer the
  // "queue after batch" path instead of forcing the operator to wait.
  const queueQ = useQuery({
    queryKey: ["po-queue", "list"],
    queryFn:  listTasks,
    refetchInterval: 5_000,
  });
  const batchActive = !!(queueQ.data?.tasks || []).find(
    (t) => t.store_id === storeId && t.kind === "batch" &&
      (t.status === "queued" || t.status === "running"),
  );

  // Streaming state
  const [phase, setPhase]       = useState<"idle" | "running" | "done" | "error">("idle");
  const [progress, setProgress] = useState<string>("");
  const [tokenTail, setTail]    = useState<string>("");
  const [markdown, setMarkdown] = useState<string>("");
  const [errMsg, setErr]        = useState<string>("");
  const [refineMsg, setRefine]  = useState<string>("");
  const wsRef = useRef<ReorderHandle | null>(null);

  // Tear down WS on unmount.
  useEffect(() => {
    return () => { wsRef.current?.close(); wsRef.current = null; };
  }, []);

  function start() {
    if (!storeId || !vendorId) return;
    wsRef.current?.close();
    setPhase("running"); setProgress(""); setTail(""); setMarkdown(""); setErr("");
    const handle = openReorder(storeId, vendorId, (f) => {
      switch (f.type) {
        case "session":    /* no-op */ break;
        case "progress":   setProgress(f.content); break;
        case "token":      setTail((s) => (s + f.content).slice(-2000)); break;
        case "po_replace": setMarkdown(f.content); break;
        case "done":       setPhase("done"); persistDone(); break;
        case "error":      setPhase("error"); setErr(f.content); break;
        case "pong":       break;
      }
    });
    wsRef.current = handle;
    handle.send("generate");
  }

  function refine() {
    if (!refineMsg.trim() || !wsRef.current) return;
    setPhase("running");
    wsRef.current.edit(refineMsg.trim());
    setRefine("");
  }

  function stop() {
    wsRef.current?.stop();
  }

  async function persistDone() {
    if (!markdown) return;
    const tot = parseTotals(markdown);
    const v = vendors.data?.find(
      (x) => (x.id || x.vendor_id) === vendorId,
    );
    const sn = stores.data?.find((s) => s.store_id === storeId);
    const entry = {
      id:        `live_${storeId}_${vendorId}_${Date.now()}`,
      storeId,
      storeName: sn?.name,
      vendorId,
      vendorName: v?.name || vendorId,
      ts: Date.now(),
      markdown,
      cases:  tot.cases,
      amount: tot.amount,
    };
    usePanel.getState().upsert(entry);
    try {
      await upsertPreorder({
        store_id: entry.storeId,
        store_name: entry.storeName,
        vendor_id: entry.vendorId,
        vendor_name: entry.vendorName,
        markdown: entry.markdown,
        cases: entry.cases,
        amount: entry.amount,
        ts: entry.ts,
      });
    } catch { /* best-effort */ }
  }

  async function sendEmail() {
    if (!markdown) return;
    const tot = parseTotals(markdown);
    try {
      const r = await emailReorder({
        store_id: storeId,
        vendor_id: vendorId,
        markdown,
        cases: tot.cases,
        amount: tot.amount,
      });
      alert(`email: ${r.status} sent=${r.sent ?? 0}/${r.total ?? 0}`);
    } catch (e) {
      alert(`email failed: ${e}`);
    }
  }

  const totals = markdown ? parseTotals(markdown) : { cases: 0, amount: 0 };

  return (
    <section className="space-y-4 max-w-5xl">
      <div className="flex flex-wrap items-center gap-3">
        <label className="text-sm">{t("store.label")}</label>
        <select
          value={storeId}
          onChange={(e) => { setStoreId(e.target.value); setVendorId(""); }}
          className="border rounded px-2 py-1"
        >
          <option value="">--</option>
          {(stores.data || []).map((s) => (
            <option key={s.store_id} value={s.store_id}>
              {s.store_id} -- {s.name}
            </option>
          ))}
        </select>

        <label className="text-sm">{t("vendor.label")}</label>
        <select
          value={vendorId}
          onChange={(e) => setVendorId(e.target.value)}
          className="border rounded px-2 py-1 min-w-[14rem]"
          disabled={!storeId}
        >
          <option value="">--</option>
          {(vendors.data || []).map((v) => {
            const id = v.id || v.vendor_id || "";
            return <option key={id} value={id}>{v.name}</option>;
          })}
        </select>

        {batchActive ? (
          <button
            onClick={async () => {
              try {
                await enqueueTask({
                  store_id: storeId, kind: vendorId,
                  source: "ui", adhoc: true,
                });
                alert("queued behind running batch");
              } catch (e) { alert(`enqueue failed: ${e}`); }
            }}
            disabled={!storeId || !vendorId}
            className="bg-amber-600 text-white px-3 py-1 rounded disabled:opacity-50"
            title="batch active -- this single-vendor task will run after"
          >
            queue after batch
          </button>
        ) : (
          <button
            onClick={start}
            disabled={!storeId || !vendorId || phase === "running"}
            className="bg-slate-900 text-white px-3 py-1 rounded disabled:opacity-50"
          >
            {phase === "running" ? "..." : t("gen.start")}
          </button>
        )}
        {phase === "running" && (
          <button onClick={stop} className="border px-3 py-1 rounded">
            {t("gen.stop")}
          </button>
        )}
        {phase === "done" && markdown && (
          <button
            onClick={sendEmail}
            className="bg-emerald-700 text-white px-3 py-1 rounded"
          >
            {t("gen.send_email")}
          </button>
        )}
        <span className="text-xs text-slate-500 ml-auto">
          {totals.cases > 0 && (
            <>
              {totals.cases} {t("po.cases")} -- $
              {totals.amount.toLocaleString(undefined, { maximumFractionDigits: 0 })}
            </>
          )}
        </span>
      </div>

      {progress && phase === "running" && (
        <p className="text-xs text-slate-500">{progress}</p>
      )}
      {errMsg && (
        <p className="text-sm text-red-700">{t("common.error")}: {errMsg}</p>
      )}

      {!markdown && phase === "idle" && (
        <p className="text-sm text-slate-500">{t("gen.no_session")}</p>
      )}

      {markdown && (
        <div className="border rounded p-4 bg-white">
          <Markdown text={markdown} />
        </div>
      )}

      {(phase === "running" || phase === "done") && (
        <details className="text-xs">
          <summary className="cursor-pointer text-slate-500">token tail (debug)</summary>
          <pre className="font-mono whitespace-pre-wrap p-2 bg-slate-50 max-h-40 overflow-y-auto">
            {tokenTail}
          </pre>
        </details>
      )}

      {phase === "done" && (
        <div className="flex gap-2">
          <input
            value={refineMsg}
            onChange={(e) => setRefine(e.target.value)}
            placeholder={t("gen.refine_hint")}
            className="flex-1 border rounded px-3 py-2 text-sm"
            onKeyDown={(e) => { if (e.key === "Enter") refine(); }}
          />
          <button
            onClick={refine}
            className="bg-slate-900 text-white px-3 py-2 rounded text-sm"
          >
            {t("gen.refine")}
          </button>
        </div>
      )}
    </section>
  );
}
