import { api } from "./api";

export interface EmailReorderInput {
  store_id: string;
  vendor_id: string;
  markdown: string;
  cases?: number;
  amount?: number;
}

export interface EmailResult {
  status: string;
  sent?: number;
  total?: number;
  recipients?: string[];
  vendor_count?: number;
  detail?: string;
}

export async function emailReorder(input: EmailReorderInput): Promise<EmailResult> {
  return api<EmailResult>("/api/reorder/email", {
    method: "POST",
    body: JSON.stringify(input),
  });
}

export async function sendDigest(
  storeId: string, kind: "transfer" | "order", sinceMs: number,
): Promise<EmailResult> {
  return api<EmailResult>(
    `/api/admin/po-digest/${encodeURIComponent(storeId)}/${kind}?since_ms=${sinceMs}`,
    { method: "POST" },
  );
}
