import { useState } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { login } from "../lib/auth";

interface LocState { from?: string }

export default function LoginPage() {
  const nav  = useNavigate();
  const loc  = useLocation();
  const from = (loc.state as LocState | null)?.from || "/queue";

  const [u, setU]   = useState("");
  const [p, setP]   = useState("");
  const [busy, setBusy] = useState(false);
  const [err, setErr]   = useState<string | null>(null);

  async function onSubmit(e: React.FormEvent) {
    e.preventDefault();
    setErr(null); setBusy(true);
    try {
      await login(u.trim(), p);
      nav(from, { replace: true });
    } catch (ex) {
      setErr(ex instanceof Error ? ex.message : String(ex));
    } finally {
      setBusy(false);
    }
  }

  return (
    <section className="max-w-sm mx-auto mt-12 space-y-4">
      <h2 className="text-lg font-semibold">Sign in</h2>
      <form onSubmit={onSubmit} className="space-y-3">
        <input
          autoFocus
          className="w-full border rounded px-3 py-2"
          placeholder="username"
          value={u}
          onChange={(e) => setU(e.target.value)}
        />
        <input
          type="password"
          className="w-full border rounded px-3 py-2"
          placeholder="password"
          value={p}
          onChange={(e) => setP(e.target.value)}
        />
        <button
          disabled={busy || !u || !p}
          className="w-full bg-slate-900 text-white rounded py-2 disabled:opacity-50"
        >
          {busy ? "..." : "Sign in"}
        </button>
        {err && <p className="text-red-700 text-sm">{err}</p>}
      </form>
      <p className="text-xs text-slate-500">
        Token shared with legacy UI at <a className="underline" href="/">/</a>.
      </p>
    </section>
  );
}
