import { create } from "zustand";
import { persist } from "zustand/middleware";
import { D, type Lang } from "./dict";

interface I18nState {
  lang: Lang;
  setLang: (l: Lang) => void;
}

export const useI18n = create<I18nState>()(
  persist(
    (set) => ({
      lang: "zh",
      setLang: (l: Lang) => set({ lang: l }),
    }),
    { name: "eip_lang" },
  ),
);

export function useT(): (key: keyof typeof D) => string {
  const lang = useI18n((s) => s.lang);
  return (key) => {
    const e = D[key];
    if (!e) return String(key);
    return e[lang];
  };
}
