import { useQuery } from "@tanstack/react-query";
import { Navigate, useLocation } from "react-router-dom";

/**
 * Wrap routes that require login. If the token is missing OR the
 * /api/auth/me check fails, redirect to /login with the original
 * destination in `state.from`.
 *
 * If user_auth is disabled on the backend (no auth.json), the /me
 * endpoint will never have been called because getToken() is empty
 * AND the auth gate middleware will admit unauthenticated requests
 * -- in that case `me()` returns null but every page still works.
 * To detect "auth not required" we instead probe /api/auth/me
 * unconditionally; a 200 means logged in OR auth disabled, both OK.
 */
export default function AuthGate({ children }: { children: React.ReactNode }) {
  const loc = useLocation();
  const q = useQuery({
    queryKey: ["auth-me"],
    queryFn: async () => {
      // Try /me. If 200 -> good. If 401 -> redirect.
      try {
        const r = await fetch("/api/auth/me", {
          headers: tokenHeader(),
          credentials: "same-origin",
        });
        if (r.status === 401) return { ok: false as const };
        return { ok: true as const };
      } catch {
        return { ok: true as const };  // network blip: don't lock out
      }
    },
    staleTime: 60_000,
  });

  if (q.isLoading) return <p className="p-4 text-slate-500">checking auth ...</p>;
  if (q.data && !q.data.ok) {
    return <Navigate to="/login" state={{ from: loc.pathname }} replace />;
  }
  return <>{children}</>;
}

function tokenHeader(): HeadersInit {
  const t = localStorage.getItem("eip_auth_token") || "";
  return t ? { Authorization: `Bearer ${t}` } : {};
}
