import { create } from "zustand";
import { persist } from "zustand/middleware";

/**
 * Currently selected store_id. Persisted via localStorage so a
 * refresh keeps the user's last pick. Same key shape as legacy
 * (`eip_selected_store`) so both UIs see the same selection.
 */
interface SelectedStoreState {
  storeId: string;
  setStoreId: (id: string) => void;
}

export const useSelectedStore = create<SelectedStoreState>()(
  persist(
    (set) => ({
      storeId: "",
      setStoreId: (id: string) => set({ storeId: id }),
    }),
    { name: "eip_selected_store" },
  ),
);
