import { api, API_BASE, getToken } from "./api";

export type DraftStatus = "pending" | "approved" | "rejected" | "committed";

export interface DraftLine {
  sku?: string;
  description?: string;
  product_name?: string;
  qty?: number;
  unit_cost?: number;
  line_total?: number;
  confidence?: number;
  match_score?: number;
  notes?: string;
}

export interface Draft {
  id: string;
  store_id: string;
  vendor_id?: string;
  vendor_name?: string;
  vendor_invoice_no?: string;
  invoice_date?: string;
  status: DraftStatus;
  created_at: number;
  total?: number;
  cases?: number;
  invoice_no?: string;
  source?: string;
  image_path?: string;
  lines?: DraftLine[];
  hints?: { ts: number; hint: string }[];
}

export async function listDrafts(): Promise<Draft[]> {
  const r = await api<{ items: Draft[] } | Draft[]>("/api/admin/po-drafts");
  if (Array.isArray(r)) return r;
  return r.items || [];
}

export async function getDraft(id: string): Promise<Draft> {
  return api<Draft>(`/api/admin/po-drafts/${encodeURIComponent(id)}`);
}

export async function previewDraft(id: string): Promise<{ html: string }> {
  return api(`/api/admin/po-drafts/${encodeURIComponent(id)}/preview`);
}

export async function editDraft(
  id: string,
  body: { lines?: DraftLine[]; vendor_id?: string; vendor_name?: string;
          vendor_invoice_no?: string; invoice_date?: string; actor?: string },
): Promise<void> {
  await api(`/api/admin/po-drafts/${encodeURIComponent(id)}/edit`, {
    method: "POST",
    body: JSON.stringify({ actor: "admin", ...body }),
  });
}

export async function rescanDraft(
  id: string, hint: string,
): Promise<{ lines: DraftLine[]; hints: { ts: number; hint: string }[] }> {
  return api(`/api/admin/po-drafts/${encodeURIComponent(id)}/rescan`, {
    method: "POST",
    body: JSON.stringify({ hint, actor: "admin" }),
  });
}

export async function approveDraft(id: string, password: string): Promise<void> {
  await api(`/api/admin/po-drafts/${encodeURIComponent(id)}/approve`, {
    method: "POST",
    body: JSON.stringify({ password }),
  });
}

export async function rejectDraft(id: string, reason: string): Promise<void> {
  await api(`/api/admin/po-drafts/${encodeURIComponent(id)}/reject`, {
    method: "POST",
    body: JSON.stringify({ reason }),
  });
}

export async function deleteDraft(id: string): Promise<void> {
  await api(`/api/admin/po-drafts/${encodeURIComponent(id)}`, { method: "DELETE" });
}

export async function commitDraft(id: string, password: string): Promise<void> {
  await api(`/api/admin/po-drafts/${encodeURIComponent(id)}/commit`, {
    method: "POST",
    body: JSON.stringify({ password }),
  });
}

/**
 * Multipart invoice upload. Returns the created draft (with parsed
 * lines + matched SKUs).
 */
export async function uploadInvoice(args: {
  file: File;
  storeId: string;
  createdBy?: string;
}): Promise<Draft> {
  const fd = new FormData();
  fd.append("file", args.file);
  fd.append("store_id", args.storeId);
  fd.append("created_by", args.createdBy || "admin");

  const headers: Record<string, string> = {};
  const tok = getToken();
  if (tok) headers["Authorization"] = `Bearer ${tok}`;
  const r = await fetch(API_BASE + "/api/admin/invoice-ocr", {
    method: "POST",
    body: fd,
    headers,
    credentials: API_BASE ? "include" : "same-origin",
  });
  if (!r.ok) {
    const text = await r.text().catch(() => "");
    throw new Error(`HTTP ${r.status}: ${text.slice(0, 300)}`);
  }
  return (await r.json()) as Draft;
}

// Staging
export interface StagingRow {
  stage_id: string;
  draft_id: string;
  committed_at: number;
  store_id: string;
  vendor_name?: string;
}

export async function listStaging(): Promise<StagingRow[]> {
  const r = await api<{ items: StagingRow[] } | StagingRow[]>("/api/admin/staging");
  if (Array.isArray(r)) return r;
  return r.items || [];
}
