/**
 * REST + WS endpoints + auth token plumbing.
 *
 * Mirror of the legacy index.html boundary helpers (API_BASE / WS_BASE
 * / token Bearer fallback) so the React app talks to the same backend
 * with identical auth semantics. Single source: change here only.
 */

// In dev, Vite proxies /api -> http://127.0.0.1 and /ws -> ws://127.0.0.1
// (see vite.config.ts). In prod, the React bundle is served from
// ui-lo.empireintegration.com/r/ -- API at api-lo.empireintegration.com.
const HOST = typeof window !== "undefined" ? window.location.hostname : "";
export const API_BASE: string =
  HOST === "ui-lo.empireintegration.com" ? "https://api-lo.empireintegration.com" : "";
export const WS_BASE: string = API_BASE ? API_BASE.replace(/^http/, "ws") : "";

// Same key the legacy index.html uses, so a login on either UI is
// shared across both during the strangler period.
const TOKEN_KEY = "eip_auth_token";

export function getToken(): string {
  return localStorage.getItem(TOKEN_KEY) || "";
}

export function setToken(t: string): void {
  if (t) localStorage.setItem(TOKEN_KEY, t);
  else localStorage.removeItem(TOKEN_KEY);
}

/** Fetch with auth + JSON convenience. Throws on !ok. */
export async function api<T = unknown>(
  path: string,
  init: RequestInit = {},
): Promise<T> {
  const headers = new Headers(init.headers || {});
  if (!headers.has("Content-Type") && init.body) {
    headers.set("Content-Type", "application/json");
  }
  const tok = getToken();
  if (tok && !headers.has("Authorization")) {
    headers.set("Authorization", `Bearer ${tok}`);
  }
  const r = await fetch(API_BASE + path, {
    ...init,
    headers,
    credentials: API_BASE ? "include" : "same-origin",
  });
  if (!r.ok) {
    const text = await r.text().catch(() => "");
    throw new Error(`HTTP ${r.status} ${path}: ${text.slice(0, 300)}`);
  }
  if (r.status === 204) return undefined as T;
  return (await r.json()) as T;
}

export function wsUrl(path: string): string {
  if (WS_BASE) return WS_BASE + path;
  const proto = window.location.protocol === "https:" ? "wss:" : "ws:";
  return `${proto}//${window.location.host}${path}`;
}
