import { api } from "./api";

export interface PreorderRow {
  store_id: string;
  store_name?: string;
  vendor_id: string;
  vendor_name: string;
  ts: number;     // ms epoch
  markdown: string;
  cases: number;
  amount: number;
}

export async function listPreorders(): Promise<PreorderRow[]> {
  const r = await api<{ items: PreorderRow[] }>("/api/admin/preorders");
  return r.items || [];
}

export async function upsertPreorder(p: PreorderRow): Promise<void> {
  await api("/api/admin/preorders/upsert", {
    method: "POST",
    body: JSON.stringify(p),
  });
}

export async function clearAllPreorders(): Promise<void> {
  await api("/api/admin/preorders", { method: "DELETE" });
}
