import { useT } from "../i18n/useT";
import {
  useHistory, moveHistoryToPanel, type VendorEntry,
} from "../stores/poStore";

export default function HistoryPage() {
  const t = useT();
  const hist = useHistory();
  const entries = hist.entries.slice().sort((a, b) => (b.ts || 0) - (a.ts || 0));
  return (
    <section className="space-y-3 max-w-5xl">
      <h2 className="text-lg font-semibold">{t("hist.archive")}</h2>
      {entries.length === 0 ? (
        <p className="text-slate-500 text-sm">{t("hist.empty")}</p>
      ) : (
        <ul className="divide-y border rounded bg-white">
          {entries.map((e) => (
            <Row key={e.id} e={e} />
          ))}
        </ul>
      )}
    </section>
  );
}

function Row({ e }: { e: VendorEntry }) {
  const t = useT();
  return (
    <li className="p-3 flex items-center gap-3 text-sm">
      <span className="text-xs text-slate-500 w-32">
        {e.storeName || e.storeId}
      </span>
      <span className="font-medium flex-1">{e.vendorName}</span>
      <span className="text-xs text-slate-500">
        {e.cases} {t("po.cases")} -- ${e.amount.toLocaleString(undefined, { maximumFractionDigits: 0 })}
      </span>
      <span className="text-xs text-slate-500 w-32">
        {new Date(e.ts).toLocaleString()}
      </span>
      <button
        onClick={() => moveHistoryToPanel(e.id)}
        className="underline text-blue-700 text-xs"
      >
        {t("hist.restore")}
      </button>
    </li>
  );
}
