import { useEffect } from "react";
import { Link } from "react-router-dom";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import {
  enqueueTask, listTasks, cancelTask,
  subscribeGlobal, type QueueTask,
} from "../lib/queue";
import { listStores } from "../lib/stores";
import { useSelectedStore } from "../stores/selectedStore";

/**
 * Server-side queue control panel.
 *  - Top: store selector + "Run batch for <store>" enqueue button.
 *  - Below: live list, status auto-refreshes from /ws/queue-events.
 *  - Each row links to /r/task/:id for per-task token stream.
 */
export default function QueuePage() {
  const qc = useQueryClient();
  const { storeId, setStoreId } = useSelectedStore();
  const stores = useQuery({ queryKey: ["stores"], queryFn: listStores });
  const tasks  = useQuery({ queryKey: ["po-queue", "list"], queryFn: listTasks });

  useEffect(() => {
    if (!storeId && stores.data && stores.data.length > 0) {
      setStoreId(String(stores.data[0].store_id));
    }
  }, [storeId, stores.data, setStoreId]);

  useEffect(() => {
    const off = subscribeGlobal((evt) => {
      if (
        evt.type === "task_started" || evt.type === "task_done" ||
        evt.type === "task_failed"  || evt.type === "task_cancelled" ||
        evt.type === "vendor_done"  || evt.type === "phase_done" ||
        evt.type === "email_sent"
      ) {
        qc.invalidateQueries({ queryKey: ["po-queue", "list"] });
      }
    });
    return off;
  }, [qc]);

  const enqueue = useMutation({
    mutationFn: () => enqueueTask({ store_id: storeId, kind: "batch", source: "ui" }),
    onSuccess: () => qc.invalidateQueries({ queryKey: ["po-queue", "list"] }),
  });

  const cancel = useMutation({
    mutationFn: (taskId: string) => cancelTask(taskId),
    onSuccess: () => qc.invalidateQueries({ queryKey: ["po-queue", "list"] }),
  });

  const storeName =
    stores.data?.find((s) => String(s.store_id) === storeId)?.name || storeId;

  return (
    <section className="space-y-6 max-w-4xl">
      <div className="flex items-center gap-3">
        <label className="text-sm">Store:</label>
        <select
          value={storeId}
          onChange={(e) => setStoreId(e.target.value)}
          className="border rounded px-2 py-1"
        >
          {(stores.data || []).map((s) => (
            <option key={s.store_id} value={s.store_id}>
              {s.store_id} -- {s.name}
            </option>
          ))}
        </select>
        <button
          disabled={!storeId || enqueue.isPending}
          onClick={() => enqueue.mutate()}
          className="bg-slate-900 text-white px-3 py-1 rounded disabled:opacity-50"
        >
          {enqueue.isPending ? "..." : `Run batch for ${storeName}`}
        </button>
        {enqueue.isError && (
          <span className="text-red-700 text-sm">{String(enqueue.error)}</span>
        )}
      </div>

      <div>
        <h2 className="text-lg font-semibold mb-2">
          Today's tasks ({tasks.data?.tasks.length || 0})
        </h2>
        {tasks.isLoading ? (
          <p>loading ...</p>
        ) : tasks.isError ? (
          <p className="text-red-700">queue: {String(tasks.error)}</p>
        ) : (tasks.data?.tasks.length || 0) === 0 ? (
          <p className="text-slate-500 text-sm">queue is empty</p>
        ) : (
          <table className="w-full text-sm border-collapse">
            <thead className="bg-slate-100">
              <tr>
                <th className="text-left p-2">store</th>
                <th className="text-left p-2">kind</th>
                <th className="text-left p-2">status</th>
                <th className="text-left p-2">source</th>
                <th className="text-left p-2">enqueued</th>
                <th className="text-left p-2">finished</th>
                <th className="text-left p-2">actions</th>
              </tr>
            </thead>
            <tbody>
              {tasks.data!.tasks.map((t) => (
                <Row
                  key={t.task_id}
                  t={t}
                  onCancel={() => cancel.mutate(t.task_id)}
                />
              ))}
            </tbody>
          </table>
        )}
      </div>
    </section>
  );
}

function Row({ t, onCancel }: { t: QueueTask; onCancel: () => void }) {
  const cls = {
    queued:    "text-slate-600",
    running:   "text-blue-700 font-medium",
    done:      "text-emerald-700",
    failed:    "text-red-700",
    cancelled: "text-amber-700",
  }[t.status];
  const active = t.status === "queued" || t.status === "running";
  return (
    <tr className="border-b">
      <td className="p-2">{t.store_id}</td>
      <td className="p-2 font-mono">{t.kind}</td>
      <td className={`p-2 ${cls}`}>{t.status}</td>
      <td className="p-2">{t.source}</td>
      <td className="p-2 text-xs">{fmt(t.enqueued_at)}</td>
      <td className="p-2 text-xs">{t.finished_at ? fmt(t.finished_at) : "-"}</td>
      <td className="p-2 text-xs space-x-2">
        <Link to={`/task/${t.task_id}`} className="text-blue-700 underline">
          view
        </Link>
        {active && (
          <button onClick={onCancel} className="text-red-700 underline">
            cancel
          </button>
        )}
      </td>
    </tr>
  );
}

function fmt(epoch: number): string {
  return new Date(epoch * 1000).toLocaleTimeString();
}
