/**
 * Auth: login / me / logout. Reads the same backend endpoints the
 * legacy UI uses; token shared via the same localStorage key.
 */
import { api, getToken, setToken } from "./api";

export interface MeResponse {
  username: string;
}

export async function login(username: string, password: string): Promise<string> {
  const r = await api<{ token: string }>("/api/auth/login", {
    method: "POST",
    body: JSON.stringify({ username, password }),
  });
  setToken(r.token);
  return r.token;
}

export async function me(): Promise<MeResponse | null> {
  if (!getToken()) return null;
  try {
    return await api<MeResponse>("/api/auth/me");
  } catch {
    setToken("");   // bad token -> clear
    return null;
  }
}

export async function logout(): Promise<void> {
  try { await api("/api/auth/logout", { method: "POST" }); }
  catch { /* ignore */ }
  setToken("");
}
