import { useI18n } from "../i18n/useT";

export default function LangSwitcher() {
  const { lang, setLang } = useI18n();
  return (
    <button
      onClick={() => setLang(lang === "zh" ? "en" : "zh")}
      className="text-xs underline opacity-80"
      title="toggle language"
    >
      {lang === "zh" ? "EN" : "中"}
    </button>
  );
}
