import { useQuery } from "@tanstack/react-query";
import { api } from "../lib/api";

interface HealthResponse {
  status: "ok" | "degraded";
  sql: Record<string, { ok: boolean; error?: string }>;
  llm: Record<string, unknown>;
}

export default function HealthPage() {
  const q = useQuery({
    queryKey: ["health"],
    queryFn: () => api<HealthResponse>("/health"),
    refetchInterval: 10_000,
  });

  if (q.isLoading) return <p>checking ...</p>;
  if (q.isError)   return <p className="text-red-700">health: {String(q.error)}</p>;

  const h = q.data!;
  return (
    <section className="space-y-4">
      <h2 className="text-lg font-semibold">
        Backend status:{" "}
        <span className={h.status === "ok" ? "text-emerald-700" : "text-amber-700"}>
          {h.status}
        </span>
      </h2>
      <div>
        <h3 className="font-medium mb-1">SQL pools</h3>
        <ul className="text-sm font-mono">
          {Object.entries(h.sql).map(([k, v]) => (
            <li key={k}>
              {k}: {v.ok ? "ok" : `FAIL (${v.error || ""})`}
            </li>
          ))}
        </ul>
      </div>
      <div>
        <h3 className="font-medium mb-1">LLM provider</h3>
        <pre className="text-xs bg-slate-100 p-2 rounded">
          {JSON.stringify(h.llm, null, 2)}
        </pre>
      </div>
    </section>
  );
}
