/**
 * Recompute (cases, amount) from a PO markdown body. The legacy UI
 * trusts the parser over any stored zeros from server-side regex.
 *
 * Heuristic: rows that look like `| product | N | $X.XX | ...` where
 * column 2 is a positive integer "cases" and column 3 is "$amount".
 * SKIP rows with cases=0 or markers like SKIP/-.
 */
export interface POTotals {
  cases: number;
  amount: number;
}

const LINE = /^\|\s*([^|]+?)\s*\|\s*([0-9]+)\s*\|\s*\$?([0-9,]+(?:\.[0-9]+)?)\s*\|/;

export function parseTotals(md: string): POTotals {
  let cases = 0;
  let amount = 0;
  for (const raw of (md || "").split("\n")) {
    const m = raw.match(LINE);
    if (!m) continue;
    const c = parseInt(m[2], 10);
    if (!c) continue;
    cases += c;
    amount += parseFloat(m[3].replace(/,/g, "")) || 0;
  }
  return { cases, amount };
}
