import { useEffect, useRef, useState } from "react";
import { Link, useParams } from "react-router-dom";
import { useQuery } from "@tanstack/react-query";
import {
  getTask, subscribeTask, type QueueTask, type QueueEvent,
} from "../lib/queue";

/**
 * Per-task drill-down. Subscribes to /ws/queue-task/<id> and pretty-
 * prints each milestone. Falls back to /api/po-queue/task/<id> for
 * the static row metadata (status / timestamps) so the header is
 * populated immediately even before the first WS frame arrives.
 *
 * Token-level events are filtered out of the visible log (too noisy
 * for an ops view); milestones (vendor_start, vendor_done,
 * phase_done, email_sent, task_done/failed/cancelled) get one line.
 */
export default function TaskPage() {
  const { taskId = "" } = useParams();
  const meta = useQuery({
    queryKey: ["po-queue", "task", taskId],
    queryFn:  () => getTask(taskId),
    refetchInterval: 5_000,
    enabled: !!taskId,
  });

  const [events, setEvents] = useState<QueueEvent[]>([]);
  const seen = useRef(new Set<string>());

  useEffect(() => {
    if (!taskId) return;
    setEvents([]);
    seen.current = new Set();
    const off = subscribeTask(taskId, (evt) => {
      // Dedupe replay+live overlap: the bus replays the per-topic
      // ring buffer on connect, then live tail. Same event object
      // could arrive twice if reconnect happens. Dedupe by JSON.
      const key = JSON.stringify(evt);
      if (seen.current.has(key)) return;
      seen.current.add(key);
      setEvents((es) => [...es, evt]);
    });
    return off;
  }, [taskId]);

  if (!taskId) return <p>missing task id</p>;
  return (
    <section className="space-y-4 max-w-4xl">
      <Link to="/queue" className="text-blue-700 underline text-sm">
        &lt;- back to queue
      </Link>
      <Header t={meta.data} fallbackId={taskId} />
      <div>
        <h3 className="font-medium mb-1">Live events</h3>
        <ul className="font-mono text-xs space-y-1 bg-slate-50 border rounded p-3 max-h-[60vh] overflow-y-auto">
          {events.length === 0 && (
            <li className="text-slate-500">no events yet ...</li>
          )}
          {events.map((evt, i) => (
            <li key={i}>{prettyLine(evt)}</li>
          ))}
        </ul>
      </div>
    </section>
  );
}

function Header({ t, fallbackId }: { t?: QueueTask; fallbackId: string }) {
  if (!t) return <p className="text-slate-500">task {fallbackId.slice(0, 8)} ...</p>;
  return (
    <header className="space-y-1">
      <h2 className="text-lg font-semibold">
        Task {t.task_id.slice(0, 8)} -- store {t.store_id} / {t.kind}
      </h2>
      <p className="text-sm">
        status:{" "}
        <span className={statusCls(t.status)}>{t.status}</span> -- source:{" "}
        {t.source}
      </p>
      <p className="text-xs text-slate-500">
        enqueued {fmt(t.enqueued_at)}
        {t.started_at  && <>; started {fmt(t.started_at)}</>}
        {t.finished_at && <>; finished {fmt(t.finished_at)}</>}
      </p>
      {t.error && <p className="text-sm text-red-700">error: {t.error}</p>}
    </header>
  );
}

function statusCls(s: string): string {
  return {
    queued:    "text-slate-600",
    running:   "text-blue-700 font-medium",
    done:      "text-emerald-700",
    failed:    "text-red-700",
    cancelled: "text-amber-700",
  }[s] || "";
}

function fmt(epoch: number): string {
  return new Date(epoch * 1000).toLocaleTimeString();
}

function prettyLine(evt: QueueEvent): string {
  const ts = evt.ts ? new Date(Number(evt.ts) * 1000).toLocaleTimeString() : "?";
  switch (evt.type) {
    case "task_started":
      return `[${ts}] STARTED store=${evt.store_id} kind=${evt.kind}`;
    case "phase_start":
      return `[${ts}] phase=${evt.phase} START`;
    case "phase_done":
      return `[${ts}] phase=${evt.phase} DONE  vendors=${evt.vendor_count}`;
    case "vendor_start":
      return `[${ts}]   [${evt.idx}/${evt.total}] vendor=${evt.vendor_name} (${evt.phase})`;
    case "vendor_done":
      return `[${ts}]     vendor=${evt.vendor_name} cases=${evt.cases} amount=${evt.amount} elapsed=${evt.elapsed_s}s`;
    case "vendor_failed":
      return `[${ts}]     vendor=${evt.vendor_name} FAILED ${evt.error}`;
    case "email_sent":
      return `[${ts}] EMAIL kind=${evt.kind} vendors=${evt.vendor_count} to=${(evt.recipients as string[] | undefined)?.join(",") || ""}`;
    case "task_done":
      return `[${ts}] TASK DONE`;
    case "task_failed":
      return `[${ts}] TASK FAILED: ${evt.error}`;
    case "task_cancelled":
      return `[${ts}] TASK CANCELLED`;
    case "task_status":
      return `[${ts}] (status snapshot)`;
    default:
      // Skip token-level chatter (engine_token, engine_progress)
      // unless the operator asks for it -- keep this view ops-clean.
      if (typeof evt.type === "string" && evt.type.startsWith("engine_")) {
        return "";
      }
      return `[${ts}] ${evt.type}`;
  }
}
