/**
 * Server-side batch queue: types + REST helpers + WS subscription.
 *
 * Aligns with src/backend/services/batch_queue_store.py + the
 * /api/po-queue/* + /ws/queue-* endpoints we just shipped. Same
 * dedupe semantics (business_day_iso per store) on the client view.
 */
import { api, wsUrl } from "./api";

export type QueueStatus = "queued" | "running" | "done" | "failed" | "cancelled";

export interface QueueTask {
  task_id: string;
  store_id: string;
  kind: string;          // 'batch' or vendor_id literal
  day_iso: string;
  status: QueueStatus;
  source: string;        // 'ui' | 'cli' | 'cron'
  enqueued_at: number;
  started_at: number | null;
  finished_at: number | null;
  error: string | null;
  cancel_requested: number;
  payload_json: string | null;
}

export interface QueueListResponse {
  day: string;
  tasks: QueueTask[];
}

/** POST /api/po-queue/enqueue. Returns the new task on 200 OR throws
 *  with a parseable 409 error containing existing task_id. */
export async function enqueueTask(input: {
  store_id: string;
  kind: string;
  source?: string;
  adhoc?: boolean;
}): Promise<QueueTask> {
  return api<QueueTask>("/api/po-queue/enqueue", {
    method: "POST",
    body: JSON.stringify({ source: "ui", ...input }),
  });
}

export async function listTasks(): Promise<QueueListResponse> {
  return api<QueueListResponse>("/api/po-queue/list");
}

export async function getTask(taskId: string): Promise<QueueTask> {
  return api<QueueTask>(`/api/po-queue/task/${taskId}`);
}

export async function cancelTask(taskId: string): Promise<QueueTask> {
  return api<QueueTask>(`/api/po-queue/task/${taskId}`, { method: "DELETE" });
}

// ---------- WebSocket helpers ----------

export type QueueEvent = Record<string, unknown> & { type: string };

/**
 * Subscribe to a per-task event stream. Returns a cleanup fn.
 * Auto-reconnects with backoff while the task is non-terminal.
 */
export function subscribeTask(
  taskId: string,
  onEvent: (e: QueueEvent) => void,
): () => void {
  let closed = false;
  let ws: WebSocket | null = null;
  let backoff = 1000;
  const open = () => {
    if (closed) return;
    ws = new WebSocket(wsUrl(`/ws/queue-task/${taskId}`));
    ws.onmessage = (m) => {
      try {
        const evt = JSON.parse(m.data) as QueueEvent;
        if (evt.type !== "heartbeat") onEvent(evt);
      } catch { /* ignore */ }
    };
    ws.onclose = () => {
      if (closed) return;
      setTimeout(open, backoff);
      backoff = Math.min(backoff * 2, 10_000);
    };
    ws.onerror = () => { /* onclose handles retry */ };
    ws.onopen = () => { backoff = 1000; };
  };
  open();
  return () => {
    closed = true;
    try { ws?.close(); } catch { /* ignore */ }
  };
}

/** Subscribe to global cross-browser sync stream. */
export function subscribeGlobal(
  onEvent: (e: QueueEvent) => void,
): () => void {
  let closed = false;
  let ws: WebSocket | null = null;
  let backoff = 1000;
  const open = () => {
    if (closed) return;
    ws = new WebSocket(wsUrl("/ws/queue-events"));
    ws.onmessage = (m) => {
      try {
        const evt = JSON.parse(m.data) as QueueEvent;
        if (evt.type !== "heartbeat") onEvent(evt);
      } catch { /* ignore */ }
    };
    ws.onclose = () => {
      if (closed) return;
      setTimeout(open, backoff);
      backoff = Math.min(backoff * 2, 10_000);
    };
    ws.onerror = () => { /* onclose handles retry */ };
    ws.onopen = () => { backoff = 1000; };
  };
  open();
  return () => {
    closed = true;
    try { ws?.close(); } catch { /* ignore */ }
  };
}
