/**
 * /ws/reorder protocol bridge.
 *
 * Server -> Client frames (one of):
 *   {type: "session",   content: "<saga uuid>"}
 *   {type: "progress",  content: "..."}
 *   {type: "token",     content: "..."}
 *   {type: "po_replace",content: "<full markdown>"}
 *   {type: "done",      content: ""}
 *   {type: "error",     content: "..."}
 *   {type: "pong"}
 *
 * Client -> Server actions:
 *   {action: "generate"}
 *   {action: "edit", message: "..."}
 *   {action: "stop"}
 *   {action: "ping"}
 */
import { wsUrl } from "./api";

export type ReorderFrame =
  | { type: "session";    content: string }
  | { type: "progress";   content: string }
  | { type: "token";      content: string }
  | { type: "po_replace"; content: string }
  | { type: "done";       content: string }
  | { type: "error";      content: string }
  | { type: "pong" };

export interface ReorderHandle {
  send: (action: "generate") => void;
  edit: (message: string) => void;
  stop: () => void;
  close: () => void;
  socket: WebSocket;
}

export function openReorder(
  storeId: string,
  vendorId: string,
  onFrame: (f: ReorderFrame) => void,
  onClose?: (e: CloseEvent) => void,
): ReorderHandle {
  const url = wsUrl(
    `/ws/reorder?store_id=${encodeURIComponent(storeId)}&vendor_id=${encodeURIComponent(vendorId)}`,
  );
  const ws = new WebSocket(url);
  ws.onmessage = (m) => {
    try {
      const f = JSON.parse(m.data) as ReorderFrame;
      onFrame(f);
    } catch { /* ignore */ }
  };
  ws.onclose = (e) => onClose?.(e);
  // Heartbeat: client must ping every <40s or the server tears down.
  const hb = setInterval(() => {
    if (ws.readyState === WebSocket.OPEN) ws.send(JSON.stringify({ action: "ping" }));
  }, 30_000);
  ws.addEventListener("close", () => clearInterval(hb));
  return {
    socket: ws,
    send: (action) => ws.send(JSON.stringify({ action })),
    edit: (message) => ws.send(JSON.stringify({ action: "edit", message })),
    stop: () => ws.send(JSON.stringify({ action: "stop" })),
    close: () => { try { ws.close(1000); } catch { /* ignore */ } },
  };
}
