import { useState } from "react";
import { Link } from "react-router-dom";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import {
  listDrafts, deleteDraft, approveDraft, rejectDraft, commitDraft,
  type Draft, type DraftStatus,
} from "../../lib/drafts";
import { useT } from "../../i18n/useT";

export default function DraftsPage() {
  const t  = useT();
  const qc = useQueryClient();
  const q  = useQuery({ queryKey: ["drafts"], queryFn: listDrafts });

  const del = useMutation({
    mutationFn: (id: string) => deleteDraft(id),
    onSuccess: () => qc.invalidateQueries({ queryKey: ["drafts"] }),
  });

  if (q.isLoading) return <p>{t("common.loading")}</p>;
  if (q.isError)   return <p className="text-red-700">{String(q.error)}</p>;

  const drafts = q.data || [];
  return (
    <section className="space-y-3 max-w-6xl">
      <h2 className="text-lg font-semibold">{t("admin.drafts")} ({drafts.length})</h2>
      {drafts.length === 0 ? (
        <p className="text-slate-500 text-sm">no drafts</p>
      ) : (
        <table className="w-full text-sm border-collapse">
          <thead className="bg-slate-100">
            <tr>
              <th className="text-left p-2">id</th>
              <th className="text-left p-2">store</th>
              <th className="text-left p-2">vendor</th>
              <th className="text-right p-2">cases</th>
              <th className="text-right p-2">total</th>
              <th className="text-left p-2">status</th>
              <th className="text-left p-2">created</th>
              <th className="text-left p-2">actions</th>
            </tr>
          </thead>
          <tbody>
            {drafts.map((d) => (
              <DraftRow key={d.id} d={d} onDelete={() => del.mutate(d.id)} />
            ))}
          </tbody>
        </table>
      )}
    </section>
  );
}

function DraftRow({ d, onDelete }: { d: Draft; onDelete: () => void }) {
  const t  = useT();
  const qc = useQueryClient();
  const [busy, setBusy] = useState(false);

  async function approve() {
    const pwd = prompt("admin password:");
    if (!pwd) return;
    setBusy(true);
    try { await approveDraft(d.id, pwd); qc.invalidateQueries({ queryKey: ["drafts"] }); }
    catch (e) { alert(`approve failed: ${e}`); }
    finally  { setBusy(false); }
  }
  async function commit() {
    const pwd = prompt("admin password:");
    if (!pwd) return;
    setBusy(true);
    try { await commitDraft(d.id, pwd); qc.invalidateQueries({ queryKey: ["drafts"] }); }
    catch (e) { alert(`commit failed: ${e}`); }
    finally  { setBusy(false); }
  }
  async function reject() {
    const reason = prompt("reject reason:");
    if (!reason) return;
    setBusy(true);
    try { await rejectDraft(d.id, reason); qc.invalidateQueries({ queryKey: ["drafts"] }); }
    catch (e) { alert(`reject failed: ${e}`); }
    finally  { setBusy(false); }
  }

  return (
    <tr className="border-b">
      <td className="p-2 font-mono text-xs">{d.id.slice(0, 12)}</td>
      <td className="p-2">{d.store_id}</td>
      <td className="p-2">{d.vendor_name || d.vendor_id || "-"}</td>
      <td className="p-2 text-right">{d.cases ?? "-"}</td>
      <td className="p-2 text-right">{d.total ? `$${d.total.toLocaleString()}` : "-"}</td>
      <td className={`p-2 ${statusCls(d.status)}`}>{d.status}</td>
      <td className="p-2 text-xs">{new Date(d.created_at * 1000).toLocaleString()}</td>
      <td className="p-2 text-xs space-x-2">
        <Link to={`/admin/drafts/${d.id}`} className="text-blue-700 underline">
          view
        </Link>
        {d.status === "pending"  && (
          <>
            <button onClick={approve} disabled={busy} className="underline text-emerald-700">{t("admin.approve")}</button>
            <button onClick={reject}  disabled={busy} className="underline text-red-700">{t("admin.reject")}</button>
          </>
        )}
        {d.status === "approved" && (
          <button onClick={commit}   disabled={busy} className="underline text-blue-700">{t("admin.commit")}</button>
        )}
        <button onClick={onDelete} className="underline text-slate-500">{t("common.delete")}</button>
      </td>
    </tr>
  );
}

function statusCls(s: DraftStatus): string {
  return {
    pending:   "text-slate-600",
    approved:  "text-blue-700",
    rejected:  "text-red-700",
    committed: "text-emerald-700",
  }[s] || "";
}
