import { Routes, Route, NavLink, Navigate, Outlet } from "react-router-dom";
import HealthPage from "./pages/HealthPage";
import QueuePage from "./pages/QueuePage";
import TaskPage from "./pages/TaskPage";
import GeneratePage from "./pages/GeneratePage";
import POPanelPage from "./pages/POPanelPage";
import HistoryPage from "./pages/HistoryPage";
import LoginPage from "./pages/LoginPage";
import DraftsPage from "./pages/admin/DraftsPage";
import DraftDetailPage from "./pages/admin/DraftDetailPage";
import StagingPage from "./pages/admin/StagingPage";
import OcrUploadPage from "./pages/admin/OcrUploadPage";
import AuthGate from "./components/AuthGate";
import LangSwitcher from "./components/LangSwitcher";
import HolidayBanner from "./components/HolidayBanner";
import { useT } from "./i18n/useT";
import { logout } from "./lib/auth";
import { getToken } from "./lib/api";

export default function App() {
  const t = useT();
  return (
    <div className="min-h-screen flex flex-col">
      <header className="bg-slate-900 text-slate-100 px-4 py-3 flex items-center gap-3 shadow flex-wrap">
        <h1 className="font-semibold">EIP Reorder</h1>
        <nav className="flex gap-2 text-sm flex-wrap">
          <NavLink to="/queue"    className={navCls}>{t("nav.queue")}</NavLink>
          <NavLink to="/gen"      className={navCls}>{t("nav.gen")}</NavLink>
          <NavLink to="/po"       className={navCls}>PO</NavLink>
          <NavLink to="/history"  className={navCls}>{t("nav.history")}</NavLink>
          <NavLink to="/admin/drafts" className={navCls}>{t("nav.admin")}</NavLink>
          <NavLink to="/admin/ocr"    className={navCls}>OCR</NavLink>
          <NavLink to="/health"   className={navCls}>{t("nav.health")}</NavLink>
        </nav>
        <span className="ml-auto text-xs flex items-center gap-3 opacity-90">
          <LangSwitcher />
          <a href="/" className="underline">{t("nav.legacy")}</a>
          {getToken() && (
            <button
              onClick={async () => {
                await logout();
                window.location.assign("/r/login");
              }}
              className="underline"
            >
              {t("auth.logout")}
            </button>
          )}
        </span>
      </header>
      <HolidayBanner />
      <main className="flex-1 p-4">
        <Routes>
          <Route path="/login" element={<LoginPage />} />
          <Route element={<AuthLayout />}>
            <Route path="/"             element={<Navigate to="/queue" replace />} />
            <Route path="/health"       element={<HealthPage />} />
            <Route path="/queue"        element={<QueuePage />} />
            <Route path="/task/:taskId" element={<TaskPage />} />
            <Route path="/gen"          element={<GeneratePage />} />
            <Route path="/po"           element={<POPanelPage />} />
            <Route path="/history"      element={<HistoryPage />} />
            <Route path="/admin/drafts"          element={<DraftsPage />} />
            <Route path="/admin/drafts/:draftId" element={<DraftDetailPage />} />
            <Route path="/admin/staging"         element={<StagingPage />} />
            <Route path="/admin/ocr"             element={<OcrUploadPage />} />
            <Route path="*"             element={<Navigate to="/queue" replace />} />
          </Route>
        </Routes>
      </main>
    </div>
  );
}

function AuthLayout() {
  return <AuthGate><Outlet /></AuthGate>;
}

function navCls({ isActive }: { isActive: boolean }) {
  return [
    "px-2 py-1 rounded",
    isActive ? "bg-slate-700" : "hover:bg-slate-800",
  ].join(" ");
}
