import { create } from "zustand";
import { persist } from "zustand/middleware";

/**
 * PO panel + history archive.
 *
 * Mirrors the legacy index.html semantics:
 *   _poPanel.vendors == active review surface (left)
 *   _orderHistory    == archive drawer (right)
 *   Invariant: a (storeId, vendorId) pair lives in exactly ONE side.
 *
 * Same localStorage keys (`eip_po_panel_v1`, `eip_order_history_v1`)
 * so the legacy UI and React UI share state during coexistence.
 */

export interface VendorEntry {
  id: string;            // uuid or pre_<storeId>_<vendorId>
  storeId: string;
  storeName?: string;
  vendorId: string;
  vendorName: string;
  ts: number;            // ms epoch
  markdown: string;
  cases: number;
  amount: number;
  preGenerated?: boolean;  // came from server preorders, not a fresh gen
}

interface PanelState {
  vendors: VendorEntry[];
  upsert: (v: VendorEntry) => void;
  remove: (id: string) => void;
  setMarkdown: (id: string, md: string) => void;
  replaceAll: (vs: VendorEntry[]) => void;
  filterStore: (storeId: string) => VendorEntry[];
}

interface HistoryState {
  entries: VendorEntry[];
  push: (v: VendorEntry) => void;
  remove: (id: string) => void;
  replaceAll: (vs: VendorEntry[]) => void;
}

export const usePanel = create<PanelState>()(
  persist(
    (set, get) => ({
      vendors: [],
      upsert: (v) => set((s) => {
        const idx = s.vendors.findIndex(
          (x) => x.storeId === v.storeId && x.vendorId === v.vendorId,
        );
        if (idx >= 0) {
          const next = s.vendors.slice();
          next[idx] = { ...next[idx], ...v };
          return { vendors: next };
        }
        return { vendors: [v, ...s.vendors] };
      }),
      remove: (id) => set((s) => ({ vendors: s.vendors.filter((x) => x.id !== id) })),
      setMarkdown: (id, md) => set((s) => ({
        vendors: s.vendors.map((x) => (x.id === id ? { ...x, markdown: md } : x)),
      })),
      replaceAll: (vs) => set({ vendors: vs }),
      filterStore: (storeId) => get().vendors.filter((v) => v.storeId === storeId),
    }),
    { name: "eip_po_panel_v1" },
  ),
);

export const useHistory = create<HistoryState>()(
  persist(
    (set) => ({
      entries: [],
      push: (v) => set((s) => {
        const without = s.entries.filter(
          (x) => !(x.storeId === v.storeId && x.vendorId === v.vendorId),
        );
        return { entries: [v, ...without] };
      }),
      remove: (id) => set((s) => ({ entries: s.entries.filter((x) => x.id !== id) })),
      replaceAll: (vs) => set({ entries: vs }),
    }),
    { name: "eip_order_history_v1" },
  ),
);

// Move a history entry into the panel, removing it from history.
export function moveHistoryToPanel(id: string): void {
  const hist = useHistory.getState();
  const v = hist.entries.find((x) => x.id === id);
  if (!v) return;
  hist.remove(id);
  usePanel.getState().upsert(v);
}

// Move a panel vendor back to the history archive.
export function moveBackToHistory(id: string): void {
  const panel = usePanel.getState();
  const v = panel.vendors.find((x) => x.id === id);
  if (!v) return;
  panel.remove(id);
  useHistory.getState().push(v);
}
