import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useQuery } from "@tanstack/react-query";
import { listStores } from "../../lib/stores";
import { uploadInvoice } from "../../lib/drafts";
import { useSelectedStore } from "../../stores/selectedStore";
import { useT } from "../../i18n/useT";

/**
 * Invoice photo -> Gemini VLM -> auto-created draft. Same backend
 * pipeline as the legacy admin/poentry.html.
 */
export default function OcrUploadPage() {
  const t = useT();
  const nav = useNavigate();
  const { storeId, setStoreId } = useSelectedStore();
  const stores = useQuery({ queryKey: ["stores"], queryFn: listStores });
  const [file, setFile] = useState<File | null>(null);
  const [busy, setBusy] = useState(false);
  const [err, setErr]   = useState("");

  async function submit() {
    if (!file || !storeId) return;
    setBusy(true); setErr("");
    try {
      const d = await uploadInvoice({ file, storeId });
      nav(`/admin/drafts/${d.id}`);
    } catch (e) {
      setErr(String(e));
    } finally {
      setBusy(false);
    }
  }

  return (
    <section className="space-y-4 max-w-xl">
      <h2 className="text-lg font-semibold">{t("ocr.upload")}</h2>
      <div className="flex items-center gap-3">
        <label className="text-sm">{t("store.label")}</label>
        <select
          value={storeId}
          onChange={(e) => setStoreId(e.target.value)}
          className="border rounded px-2 py-1"
        >
          <option value="">--</option>
          {(stores.data || []).map((s) => (
            <option key={s.store_id} value={s.store_id}>
              {s.store_id} -- {s.name}
            </option>
          ))}
        </select>
      </div>
      <input
        type="file"
        accept="image/*"
        capture="environment"
        onChange={(e) => setFile(e.target.files?.[0] || null)}
        className="block text-sm"
      />
      {file && (
        <p className="text-xs text-slate-500">
          {file.name} -- {(file.size / 1024).toFixed(0)} KB
        </p>
      )}
      <button
        disabled={!file || !storeId || busy}
        onClick={submit}
        className="bg-slate-900 text-white px-3 py-2 rounded disabled:opacity-50"
      >
        {busy ? t("ocr.uploading") : t("ocr.upload")}
      </button>
      {err && <p className="text-sm text-red-700 whitespace-pre-wrap">{err}</p>}
    </section>
  );
}
