import { useQuery } from "@tanstack/react-query";
import { listStaging } from "../../lib/drafts";
import { useT } from "../../i18n/useT";

export default function StagingPage() {
  const t = useT();
  const q = useQuery({ queryKey: ["staging"], queryFn: listStaging });
  if (q.isLoading) return <p>{t("common.loading")}</p>;
  if (q.isError)   return <p className="text-red-700">{String(q.error)}</p>;
  const rows = q.data || [];
  return (
    <section className="space-y-3 max-w-5xl">
      <h2 className="text-lg font-semibold">{t("admin.staging")} ({rows.length})</h2>
      {rows.length === 0 ? (
        <p className="text-slate-500 text-sm">no staging entries</p>
      ) : (
        <table className="w-full text-sm border-collapse">
          <thead className="bg-slate-100">
            <tr>
              <th className="text-left p-2">stage_id</th>
              <th className="text-left p-2">draft_id</th>
              <th className="text-left p-2">store</th>
              <th className="text-left p-2">vendor</th>
              <th className="text-left p-2">committed</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((r) => (
              <tr key={r.stage_id} className="border-b">
                <td className="p-2 font-mono text-xs">{r.stage_id}</td>
                <td className="p-2 font-mono text-xs">{r.draft_id}</td>
                <td className="p-2">{r.store_id}</td>
                <td className="p-2">{r.vendor_name || "-"}</td>
                <td className="p-2 text-xs">
                  {new Date(r.committed_at * 1000).toLocaleString()}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </section>
  );
}
